/** Renders the business-specific context block every workflow prompt must include. */
function renderBrandContext(ctx) {
  return `
BRAND CONTEXT (this specific business — honor every detail)
  Business:          ${ctx.businessName} (${ctx.businessId})
  Business model:    ${ctx.businessModel}  →  activates ${ctx.businessModel.toUpperCase()} PLAYBOOK above
  Industry:          ${ctx.industry}
  Marketing stage:   ${ctx.marketingStage}${ctx.narrativeArc ? `  (narrative arc: ${ctx.narrativeArc})` : ''}
  LTV target:        ${ctx.ltv ? `$${ctx.ltv}` : 'unknown'}${ctx.cacTarget ? `   CAC ceiling: $${ctx.cacTarget}` : ''}
  Markets:           ${ctx.primaryMarkets.join(', ')}
  Languages:         ${ctx.primaryLanguages.join(', ')}
  Brand voice:       ${ctx.brandVoice ? `tone=${ctx.brandVoice.tone}; vocabulary=${ctx.brandVoice.vocabulary.slice(0, 10).join(', ')}; banned=${ctx.brandVoice.bannedWords.join(', ')}` : 'not yet defined'}
  Content pillars:   ${ctx.contentPillars ? ctx.contentPillars.map(p => `${p.name} (${p.allocation}%)`).join(' | ') : 'not yet defined'}
  Personas:          ${ctx.audience.personas.map(p => `${p.name} — JTBD: ${p.jtbd}`).join(' | ')}
  Competitors:       ${ctx.competitors?.map(c => `${c.name} (${c.position})`).join(', ') ?? 'none tracked'}
`.trim();
}

/** The full system prompt = foundation + brand context. Every workflow prepends this. */
function buildSystemPrompt(ctx, workflowAddendum) {
  return [
    FOUNDATION_SYSTEM_PROMPT,
    renderBrandContext(ctx),
    '',
    '---',
    '',
    'WORKFLOW-SPECIFIC DIRECTIVE',
    '',
    workflowAddendum,
  ].join('\n');
}


